// ─── Authority Descriptions ───────────────────────────────────────────────────

export const AUTHORITY_DESCRIPTIONS: Record<string, {
  name: string;
  description: string;
  howToUse: string;
}> = {
  "Emotional (Solar Plexus)": { name: "Emotional Authority", description: "You have a defined Solar Plexus center, which means you experience an emotional wave. Your truth is never in the moment - it reveals itself over time as you ride your emotional wave from high to low and back again.", howToUse: "Never make important decisions in the heat of the moment, whether you're feeling high or low. Wait for emotional clarity - a sense of calm knowing that comes after you've experienced the full range of your emotional wave. Sleep on important decisions. The mantra is: 'There is no truth in the now.'" },
  "Sacral": { name: "Sacral Authority", description: "Your Sacral center is your decision-making authority. It communicates through gut responses - sounds like 'uh-huh' (yes) or 'uhn-uhn' (no), and physical sensations of expansion or contraction.", howToUse: "Pay attention to your gut response when life presents you with opportunities. Ask yourself yes/no questions and notice your body's response. Your Sacral speaks in the moment through sounds and physical sensations. Trust the initial gut response - it knows before your mind does." },
  "Splenic": { name: "Splenic Authority", description: "Your Spleen center is your decision-making authority. It communicates through spontaneous intuitive hits - a quiet inner knowing about what is healthy and safe for you in the moment.", howToUse: "Trust your first instinct. The Spleen speaks only once, quietly and in the moment. It's a subtle awareness that something is right or wrong for you. Don't overthink it - your splenic awareness is faster than your mind. Pay attention to spontaneous feelings of attraction or repulsion." },
  "Ego Manifested": { name: "Ego Manifested Authority", description: "Your Heart/Ego center is connected to the Throat, giving you the authority to make decisions based on what your heart truly wants and can commit to.", howToUse: "Listen to what you truly want and what you're willing to commit your willpower to. Ask yourself: 'Is this what I really want? Am I willing to put my heart into this?' Your decisions should come from genuine desire and willpower, not obligation." },
  "Ego Projected": { name: "Ego Projected Authority", description: "Your Heart/Ego center is your authority, but it projects through the G center rather than the Throat. You need to hear yourself talk about what you want to find clarity.", howToUse: "Talk to trusted friends about your decisions and listen to what comes out of your mouth. You'll hear your truth in your own words. Pay attention to what excites your heart and what you feel genuinely willing to commit to." },
  "Self-Projected": { name: "Self-Projected Authority", description: "Your G center (Self) is your decision-making authority. You find clarity by hearing yourself speak about your identity and direction.", howToUse: "Talk to trusted people about your decisions and listen to what you say. Your truth emerges through your own voice. Pay attention to statements about identity ('I am...') and direction ('I'm going to...'). Your decisions should align with your sense of self." },
  "Mental (Outer Authority)": { name: "Mental/Environmental Authority", description: "You have no inner authority below the Throat. Your decision-making process involves talking things through with others and being in the right environment.", howToUse: "Discuss your decisions with different people and in different environments. Notice how different places and people affect your clarity. You are designed to be a sounding board for others, and in turn, you find your own clarity through dialogue and environment." },
  "Lunar (No Inner Authority)": { name: "Lunar Authority", description: "As a Reflector with no defined centers, your authority is connected to the Moon's 28-day cycle. You need a full lunar cycle to gain clarity on major decisions.", howToUse: "For important decisions, wait a full 28-day lunar cycle. During this time, discuss the decision with different people and notice how your perspective shifts day by day. Keep a moon journal. After the full cycle, you'll have a clear sense of what's right for you." },
};

