  "1/3": { name: "Investigator / Martyr", theme: "Foundation through trial and error", description: "The 1/3 profile combines the need for a solid foundation of knowledge with learning through direct experience. You are here to investigate deeply and then test what you've learned through trial and error. Your life is a journey of discovery through both study and experience.", conscious: "Line 1 (Investigator): You need to feel secure through deep knowledge and understanding. You research thoroughly before committing.", unconscious: "Line 3 (Martyr): You learn through trial and error, discovering what works and what doesn't through direct experience." },
  "1/4": { name: "Investigator / Opportunist", theme: "Foundation through networking", description: "The 1/4 profile combines deep investigation with the power of personal networks. You build a solid foundation of knowledge and then share it through your close relationships. Opportunities come through people you know.", conscious: "Line 1 (Investigator): You need thorough understanding and a secure foundation before moving forward.", unconscious: "Line 4 (Opportunist): Your opportunities and influence come through your personal network and close relationships." },
  "2/4": { name: "Hermit / Opportunist", theme: "Natural talent shared through networks", description: "The 2/4 profile combines natural talent with the power of relationships. You have innate gifts that others can see, even when you can't. Your talents are called out and shared through your personal network.", conscious: "Line 2 (Hermit): You have natural talents and need alone time to develop them. You may not see your own gifts.", unconscious: "Line 4 (Opportunist): Your opportunities come through your network. Others recognize and call out your talents." },
  "2/5": { name: "Hermit / Heretic", theme: "Natural talent with universal impact", description: "The 2/5 profile combines natural talent with the ability to offer practical solutions to others. You have innate gifts and are projected upon as someone who can solve problems. Your challenge is managing expectations.", conscious: "Line 2 (Hermit): You have natural talents and need solitude to develop them.", unconscious: "Line 5 (Heretic): Others project their expectations onto you. You have the potential to offer universal solutions." },
  "3/5": { name: "Martyr / Heretic", theme: "Trial and error with universal impact", description: "The 3/5 profile combines experiential learning with the ability to offer practical solutions. You learn through trial and error and then share your hard-won wisdom as universal solutions.", conscious: "Line 3 (Martyr): You learn through direct experience, discovering what works through trial and error.", unconscious: "Line 5 (Heretic): Others project expectations onto you. Your experiences become universal lessons." },
  "3/6": { name: "Martyr / Role Model", theme: "Trial and error becoming wisdom", description: "The 3/6 profile combines experiential learning with the potential for wisdom and role modeling. Your life has three phases: experimentation (0-30), withdrawal and observation (30-50), and becoming a role model (50+).", conscious: "Line 3 (Martyr): You learn through trial and error, especially in the first phase of life.", unconscious: "Line 6 (Role Model): You are here to eventually become a living example of wisdom gained through experience." },
  "4/6": { name: "Opportunist / Role Model", theme: "Influence through networks becoming wisdom", description: "The 4/6 profile combines the power of personal networks with the journey toward role model wisdom. Your influence comes through relationships, and over time you develop into a wise guide.", conscious: "Line 4 (Opportunist): Your opportunities and influence come through your personal network.", unconscious: "Line 6 (Role Model): You go through three life phases, eventually becoming a role model of wisdom." },
  "4/1": { name: "Opportunist / Investigator", theme: "Fixed fate through networks and knowledge", description: "The 4/1 profile is the only 'fixed fate' profile. You combine the power of personal networks with a deep foundation of knowledge. Your path is relatively fixed, and your influence comes through sharing your deep knowledge within your network.", conscious: "Line 4 (Opportunist): Your opportunities come through your personal network and relationships.", unconscious: "Line 1 (Investigator): You have a deep, unconscious need for a solid foundation of knowledge." },
  "5/1": { name: "Heretic / Investigator", theme: "Universal solutions through deep knowledge", description: "The 5/1 profile combines the ability to offer universal solutions with a deep foundation of investigation. Others project their expectations onto you, and your thorough knowledge base allows you to deliver practical solutions.", conscious: "Line 5 (Heretic): Others project expectations onto you. You have the potential to offer universal solutions.", unconscious: "Line 1 (Investigator): You have a deep, unconscious need to investigate and build a solid knowledge base." },
  "5/2": { name: "Heretic / Hermit", theme: "Universal solutions through natural talent", description: "The 5/2 profile combines the ability to offer practical solutions with natural, innate talent. Others see you as a problem-solver, and your natural gifts support this role.", conscious: "Line 5 (Heretic): Others project their expectations onto you as a problem-solver.", unconscious: "Line 2 (Hermit): You have natural talents that support your ability to offer solutions." },
  "6/2": { name: "Role Model / Hermit", theme: "Wisdom through natural talent", description: "The 6/2 profile combines the journey toward role model wisdom with natural talent. You go through three life phases, developing your innate gifts into wisdom that inspires others.", conscious: "Line 6 (Role Model): You experience three life phases, eventually becoming a wise role model.", unconscious: "Line 2 (Hermit): You have natural talents that others can see, even when you can't." },
  "6/3": { name: "Role Model / Martyr", theme: "Wisdom through experience", description: "The 6/3 profile combines the journey toward wisdom with experiential learning. Your path involves deep experimentation, especially in the first phase of life, eventually leading to profound wisdom.", conscious: "Line 6 (Role Model): You experience three life phases on the path to becoming a role model.", unconscious: "Line 3 (Martyr): You learn through trial and error, gaining wisdom through direct experience." },
